import{_ as o,o as c,c as d,a2 as i}from"./chunks/framework.CE5oItKu.js";const u=JSON.parse('{"title":"模块分层规范","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/rules/backend/05-module.md","filePath":"mango-pmo/rules/backend/05-module.md"}'),r={name:"mango-pmo/rules/backend/05-module.md"};function a(l,e,t,n,s,p){return c(),d("div",null,[...e[0]||(e[0]=[i('<h1 id="模块分层规范" tabindex="-1">模块分层规范 <a class="header-anchor" href="#模块分层规范" aria-label="Permalink to &quot;模块分层规范&quot;">​</a></h1><h2 id="_1-分层" tabindex="-1">1. 分层 <a class="header-anchor" href="#_1-分层" aria-label="Permalink to &quot;1. 分层&quot;">​</a></h2><ul><li><code>mango-app</code>：应用装配层。</li><li><code>mango-platform</code>：业务平台能力。</li><li><code>mango-infra</code>：基础设施能力。</li><li><code>mango-tools</code>：研发工具。</li></ul><h2 id="_2-模块角色" tabindex="-1">2. 模块角色 <a class="header-anchor" href="#_2-模块角色" aria-label="Permalink to &quot;2. 模块角色&quot;">​</a></h2><p>每个能力模块按需要拆成：</p><ul><li><code>api</code>：对外接口契约。</li><li><code>support</code>：对外复用支撑能力，不承载接口契约、持久化和自动装配。</li><li><code>core</code>：核心业务实现和持久化。</li><li><code>starter</code>：本地 Spring Boot 装配与对外暴露。</li><li><code>starter-*</code>：特定运行模式或外部系统适配装配，例如 <code>starter-remote</code>、<code>sync-starter</code>。</li></ul><h2 id="_3-子模块职责" tabindex="-1">3. 子模块职责 <a class="header-anchor" href="#_3-子模块职责" aria-label="Permalink to &quot;3. 子模块职责&quot;">​</a></h2><ul><li><code>api</code> 放 <code>XxxApi</code>、Command、Query、VO、Enum、注解、SPI 接口和其它对外接口契约。</li><li><code>support</code> 放其它模块 <code>core</code> 可复用的非接口契约能力，例如默认实现、扫描器、注册表、执行器、工具和适配辅助。</li><li><code>core</code> 放业务实现、实体、Mapper、转换、内部服务和持久化逻辑。</li><li><code>starter</code> 负责由 <code>XxxController</code> 实现 <code>XxxApi</code>、自动配置、Bean 注册、扫描、模块信息声明和运行时装配。</li><li><code>starter-remote</code> 负责远程调用适配、Feign adapter 和模块信息解析。</li><li>其它 <code>starter-*</code> 负责特定运行模式的自动配置和运行时装配。</li></ul><h2 id="_4-依赖规则" tabindex="-1">4. 依赖规则 <a class="header-anchor" href="#_4-依赖规则" aria-label="Permalink to &quot;4. 依赖规则&quot;">​</a></h2><ul><li><code>app</code> 依赖 <code>starter</code> 或具体 <code>starter-*</code>。</li><li><code>core</code> 只依赖其它模块 <code>api</code> 或 <code>support</code>。</li><li><code>starter</code> 依赖本域 <code>api</code> 和本域 <code>core</code>。</li><li><code>starter-remote</code> 在 <code>io.mango</code> 依赖中只允许本域 <code>api</code>、本域 <code>support</code> 和 <code>mango-infra-feign-starter</code>。</li><li><code>starter-remote</code> 的 Feign 能力必须通过 <code>mango-infra-feign-starter</code> 引入，禁止直接依赖 <code>spring-cloud-starter-openfeign</code>；其它 Spring、Web 等技术依赖按需使用外部框架坐标。</li><li>安全入口类聚合模块例外：<code>mango-security-starter-remote</code> 只允许聚合 <code>mango-infra-security-starter</code>、<code>mango-auth-starter-remote</code>、<code>mango-identity-starter-remote</code>、<code>mango-authorization-starter-remote</code>，不得新增业务实现。</li><li><code>api</code> 不依赖 <code>support</code>、<code>core</code>、<code>starter</code> 或 <code>starter-*</code>。</li><li><code>support</code> 只依赖其它模块 <code>api</code>、其它模块 <code>support</code>、<code>mango-common</code> 和必要第三方库。</li><li><code>support</code> 禁止依赖任何 <code>core</code>、<code>starter</code> 或 <code>starter-*</code>。</li><li><code>mango-infra</code> 的轻量基础设施契约应拆到 <code>*-api</code>，例如注解、实体基类、分页模型、运行期上下文句柄和 Provider/Resolver 接口。</li><li><code>mango-infra</code> 的 <code>*-starter</code> 只承载自动配置、Spring Boot 装配、扫描器、运行时实现、Flyway/MyBatis 等具体基础设施。</li><li><code>core</code> 可依赖 infra/platform/business <code>*-api</code> 和 <code>*-support</code>，禁止为了使用轻量契约或复用能力依赖 <code>*-core</code>、<code>*-starter</code> 或 <code>starter-*</code>。</li><li>已存在的 <code>core -&gt; *-starter</code> 历史依赖必须通过拆分契约到 <code>*-api</code> 后逐模块迁移，禁止放松 checker 规则。</li><li>Resource Registry 是平台能力注册边界；非 <code>mango-resource</code> 模块默认只能依赖 <code>mango-resource-api</code>，禁止直接依赖 <code>mango-resource-core</code>、<code>mango-resource-support</code>、<code>mango-resource-starter</code>、<code>mango-resource-sync-starter</code> 或 <code>mango-resource-starter-remote</code>。确需例外时，必须人工明确确认并通过 <code>mango:check</code> 参数 <code>-Dmango.check.resourceStarterDependencyExceptions=&lt;artifactId&gt;=&lt;reason&gt;</code> 记录充分理由。</li></ul><h2 id="_5-边界规则" tabindex="-1">5. 边界规则 <a class="header-anchor" href="#_5-边界规则" aria-label="Permalink to &quot;5. 边界规则&quot;">​</a></h2><ul><li><code>api</code> 不放 <code>Entity</code>、<code>Mapper</code>、<code>Controller</code>。</li><li><code>api</code> 不放 <code>@FeignClient</code>。</li><li><code>api</code> 只放其它模块会直接或间接依赖的契约类。</li><li><code>support</code> 不放业务接口契约、Controller、Feign adapter。</li><li><code>support</code> 不放 <code>@AutoConfiguration</code>、<code>AutoConfiguration.imports</code> 或 <code>module.properties</code>。</li><li><code>support</code> 不放持久化内容，包括 <code>Entity</code>、<code>Mapper</code>、<code>BaseMapper</code>、<code>ServiceImpl</code>、<code>MangoCrudServiceImpl</code>、<code>@TableName</code>、<code>db/migration</code>、MyBatis/Flyway/DataSource/JDBC/JdbcTemplate 接入。</li><li>其它模块直接依赖包括：注入、继承、实现、方法签名、远程调用契约。</li><li>本地实现协作用类型，例如 <code>*Service</code>、<code>*Manager</code>、<code>*Registry</code>、<code>*Session</code>、<code>*Dispatcher</code>，禁止放 <code>api</code>。</li><li>Controller 对外接口契约统一声明为 <code>XxxApi</code>。</li><li><code>XxxController</code> 必须实现对应 <code>XxxApi</code>，只能持有 <code>IXxxService</code> 或等效内部服务接口，禁止持有 <code>XxxApi</code> 自调用。</li><li><code>XxxFeignClient</code> 必须实现对应 <code>XxxApi</code>，只能放在 <code>starter-remote</code>。</li><li><code>XxxService</code> 必须实现 <code>IXxxService</code>，禁止直接实现 <code>XxxApi</code>。</li><li><code>IXxxService</code> 和 <code>XxxService</code> 方法签名必须遵守后端 API 规范中的 Service 入参规则。</li><li><code>core</code> 不放 <code>Controller</code>。</li><li><code>Mapper</code> 禁止跨域访问其他模块表。</li><li>跨域调用必须走 <code>XxxApi</code>。</li><li>应用装配层不承载领域实现细节。</li><li>本地聚合部署优先注入本地 <code>starter</code> 实现。</li><li>远程部署通过 <code>starter-remote</code> 调用。</li><li>远程目标服务不得写死在业务代码中。</li><li>远程目标必须通过模块信息解析。</li></ul><h2 id="_6-模块信息规则" tabindex="-1">6. 模块信息规则 <a class="header-anchor" href="#_6-模块信息规则" aria-label="Permalink to &quot;6. 模块信息规则&quot;">​</a></h2><ul><li>模块信息维护属于 <code>mango-infra-module</code>。</li><li>只有本地 <code>starter</code> 可以提供 <code>META-INF/mango/module.properties</code>。</li><li><code>api</code>、<code>core</code>、<code>starter-remote</code> 禁止声明 <code>module.properties</code>。</li><li><code>module.properties</code> 必须声明 <code>module-name</code>、<code>module-path</code>。</li><li><code>module-name</code> 必须是 Mango 模块名，禁止使用别名。</li><li><code>module-path</code> 必须在全仓唯一，禁止跨模块重合。</li><li><code>module-path</code> 表示模块正向调用前缀。</li><li><code>mango-app</code> 必须依赖 <code>mango-infra-module-starter</code>。</li><li><code>mango-infra-module-starter</code> 负责自动采集模块名、服务名和当前服务真实 contextPath。</li><li>服务名必须读取当前服务注册名。</li><li>contextPath 必须读取当前服务上下文路径。</li><li>配置覆盖必须使用 <code>mango.module.module-service</code>。</li><li>禁止新增或使用 <code>mango.remote.*</code>。</li><li>管理后台只负责查看、管理和运维模块信息。</li><li>管理后台不承载模块信息采集核心逻辑。</li></ul><h2 id="_7-remote-adapter-规则" tabindex="-1">7. Remote Adapter 规则 <a class="header-anchor" href="#_7-remote-adapter-规则" aria-label="Permalink to &quot;7. Remote Adapter 规则&quot;">​</a></h2><ul><li>Feign adapter 必须放在 <code>starter-remote</code>。</li><li>Feign adapter 必须继承本域唯一一个 <code>XxxApi</code>，禁止一个 Feign adapter 继承多个 API。</li><li><code>@FeignClient(name = &quot;...&quot;)</code> 必须填写目标模块 <code>module-name</code>。</li><li><code>@FeignClient(contextId = &quot;...&quot;)</code> 必须显式声明当前 Feign adapter 身份，默认使用 Feign 接口名 lowerCamelCase，例如 <code>AuthorizationFeignClient</code> 使用 <code>authorizationFeignClient</code>。</li><li>同一个 <code>starter-remote</code> 中相同 <code>name</code> 的多个 Feign adapter 必须使用不同 <code>contextId</code>。</li><li><code>@FeignClient(path = &quot;...&quot;)</code> 必须以目标模块 <code>module-path</code> 开头。</li><li>Feign 请求必须通过模块信息解析真实服务名和 contextPath。</li><li>Feign adapter 禁止硬编码真实服务名。</li><li>Feign adapter 禁止硬编码目标服务 contextPath。</li><li>正向调用路径统一使用 <code>/{module-path}/...</code>。</li><li>反向调用路径统一使用 <code>/_{module-path}/...</code>。</li><li><code>_</code> 只表示调用方向反转，不表示 internal / external。</li></ul><h2 id="_8-controller-path-规则" tabindex="-1">8. Controller Path 规则 <a class="header-anchor" href="#_8-controller-path-规则" aria-label="Permalink to &quot;8. Controller Path 规则&quot;">​</a></h2><ul><li>本地 <code>starter</code> 的正向 Controller 根路径必须以 <code>module-path</code> 开头。</li><li>本地 <code>starter</code> 如需接收其它同类节点的反向调用，Controller 根路径允许以 <code>/_{module-path}</code> 开头。</li><li><code>starter-remote</code> 中如果暴露反向接收 Controller，根路径必须以 <code>/_{module-path}</code> 开头。</li><li>path 只表达模块归属和调用方向，不表达内外部语义。</li></ul><h2 id="_8-1-web-边界规则" tabindex="-1">8.1 Web 边界规则 <a class="header-anchor" href="#_8-1-web-边界规则" aria-label="Permalink to &quot;8.1 Web 边界规则&quot;">​</a></h2><ul><li><code>mango-infra-web-api</code> 只放 Web 边界轻量契约，例如 <code>@Inner</code>、请求上下文 provider 接口。</li><li><code>mango-infra-web-starter</code> 只放 Spring Web 自动配置、Filter、扫描器、Servlet 实现和异常处理。</li><li><code>*-api</code> 如需声明内部接口，只允许依赖 <code>mango-infra-web-api</code> 并使用 <code>@Inner</code>；禁止依赖 <code>mango-infra-web-starter</code>。</li><li>暴露 HTTP Controller 的本地 <code>starter</code> 应依赖 <code>mango-infra-web-starter</code>，由它统一承接 Spring Web 基础设施。</li><li>依赖 <code>mango-infra-web-starter</code> 的模块禁止重复声明 <code>spring-boot-starter-web</code>。</li><li>已完成 Web 边界收敛的 <code>common</code>、<code>infra-kv</code>、<code>infra-realtime</code>、<code>infra-web</code> 不得直接依赖 <code>spring-boot-starter-web</code>。</li><li>Spring Boot 原生 Web 配置继续使用 <code>server.*</code>、<code>spring.mvc.*</code>、<code>spring.web.*</code>、<code>spring.servlet.multipart.*</code>、<code>spring.jackson.*</code> 等前缀。</li><li>Mango 只新增项目横切配置，例如 <code>mango.web.cors.*</code>、<code>mango.web.inner.*</code>、<code>mango.web.mdc.*</code>、<code>mango.web.request-context.*</code>，禁止重新包装 Spring Boot 已有通用配置。</li><li><code>@Inner</code> 只表示内部访问保护，不表示登录、权限、租户或业务可见性。</li><li>内部路径由 <code>@Inner</code> 扫描、模块 provider、数据库 provider 等来源聚合，禁止只靠 URL 前缀判定内外路径。</li></ul><h2 id="_9-命名规则" tabindex="-1">9. 命名规则 <a class="header-anchor" href="#_9-命名规则" aria-label="Permalink to &quot;9. 命名规则&quot;">​</a></h2><ul><li>对外接口使用 <code>XxxApi</code>。</li><li>模块内部服务使用 <code>IXxxService</code>。</li><li>对外 API 名称只表达跨模块能力，禁止把 <code>Registry</code>、<code>Dispatcher</code>、<code>Manager</code>、<code>Session</code> 等内部实现词放入 <code>XxxApi</code>。</li><li><code>XxxController</code> / <code>XxxFeignClient</code> 是 <code>XxxApi</code> 实现；<code>XxxService</code> 是 <code>IXxxService</code> 实现。</li><li>DIP 接口使用 <code>I...Provider</code>、<code>I...Checker</code>、<code>I...Validator</code>。</li></ul><h2 id="_10-禁止事项" tabindex="-1">10. 禁止事项 <a class="header-anchor" href="#_10-禁止事项" aria-label="Permalink to &quot;10. 禁止事项&quot;">​</a></h2><ul><li>直接依赖其他域 <code>core</code></li><li>在 <code>api</code> 放数据库对象</li><li>在 <code>api</code> 放 <code>@FeignClient</code></li><li>在 <code>core</code> 放对外接口实现</li><li>在应用装配层堆业务代码</li><li>在 <code>starter-remote</code> 中硬编码服务发现名</li><li>在 <code>starter-remote</code> 声明模块信息</li><li>在非 <code>starter</code> 模块声明 <code>module.properties</code></li><li>让管理后台承载模块信息采集核心逻辑</li></ul><h2 id="_11-相关规范" tabindex="-1">11. 相关规范 <a class="header-anchor" href="#_11-相关规范" aria-label="Permalink to &quot;11. 相关规范&quot;">​</a></h2><ul><li>模块测试放置位置、测试分层和有效测试判断，遵循 <code>mango-pmo/rules/backend/08-test.md</code>。</li></ul>',26)])])}const g=o(r,[["render",a]]);export{u as __pageData,g as default};
